const lead = $input.first().json;

const systemPrompt = `Tu es un expert en relation client pour une agence immobilière.
Ta mission : analyser le lead entrant et générer des communications personnalisées.

## Critères de température
- CHAUD (score 80-100) : projet précis, délai < 3 mois, fort engagement
- TIÈDE (score 50-79) : projet en cours, délai 3-6 mois, engagement modéré
- FROID (score 0-49) : projet vague, délai > 6 mois ou peu d'informations

## Emails à rédiger (français, ton professionnel et chaleureux)
- J0 Bienvenue : accuser réception, valeur ajoutée agence, inviter à échanger
- J2 Relance : apporter de la valeur (conseil marché, info locale), proposition concrète d'appel
- J7 Dernier contact : ton chaleureux, laisser la porte grande ouverte

Réponds UNIQUEMENT avec un JSON valide sans bloc markdown :
{
  "score": <entier 0-100>,
  "temperature": "<chaud|tiede|froid>",
  "score_raison": "<1 phrase expliquant le score>",
  "email_bienvenue": "<corps complet email J0 sans ligne d'objet>",
  "relance_j2": "<corps complet email J2 sans ligne d'objet>",
  "relance_j7": "<corps complet email J7 sans ligne d'objet>",
  "email_subjects": {
    "j0": "<objet email J0>",
    "j2": "<objet email J2>",
    "j7": "<objet email J7>"
  }
}`;

const userPrompt = `Analyse ce lead et génère les communications :

Source : ${lead.source || 'formulaire web'}
Prénom : ${lead.prenom || '(non renseigné)'}
Nom : ${lead.nom || '(non renseigné)'}
Email : ${lead.email || ''}
Téléphone : ${lead.tel || '(non renseigné)'}
Bien recherché : ${lead.bien || '(non précisé)'}
Ville : ${lead.ville || '(non précisée)'}
Projet : ${lead.projet || '(non précisé)'}
Message : ${lead.message || '(aucun message)'}`;

return [{ json: { ...lead, _systemPrompt: systemPrompt, _userPrompt: userPrompt } }];

const claudeResponse = $input.first().json;
const lead = $('Construire Prompt Claude').first().json;

// Extraire le texte de la réponse Claude
const rawText = claudeResponse.content?.[0]?.text || '';

// Parser le JSON retourné par Claude
let parsed;
try {
  const cleaned = rawText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Parse Claude impossible. Réponse : ' + rawText.substring(0, 300));
}

if (!parsed.score || !parsed.temperature || !parsed.email_bienvenue) {
  throw new Error('Réponse Claude incomplète : ' + JSON.stringify(parsed).substring(0, 200));
}

// Convertir texte en HTML lisible
function toHtml(text) {
  if (!text) return '<p></p>';
  const escaped = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  return '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.7;color:#333;">'
    + '<p>' + escaped.replace(/\n\n+/g, '</p><p>').replace(/\n/g, '<br>') + '</p>'
    + '</div>';
}

// Variables d'environnement n8n
const agentName   = $vars.AGENT_NAME   || 'Votre agence';
const agentEmail  = $vars.AGENT_EMAIL  || 'contact@agence.com';
const senderEmail = $vars.SENDER_EMAIL || agentEmail;

const fullName = [lead.prenom, lead.nom].filter(Boolean).join(' ') || lead.email;
const temp = (parsed.temperature || 'froid').toLowerCase();
const tempLabel = temp === 'chaud' ? '🔥 CHAUD' : temp === 'tiede' ? '🌤️ TIÈDE' : '❄️ FROID';

const subjects = parsed.email_subjects || {};
const j0Subject = subjects.j0 || 'Votre demande immobilière';
const j2Subject = subjects.j2 || 'Un suivi sur votre projet';
const j7Subject = subjects.j7 || 'Toujours disponible pour vous';

const sender = { name: agentName, email: senderEmail };
const leadRecipient = [{ email: lead.email, name: fullName }];

// Payloads Brevo pré-construits (JSON strings) réutilisés après les Wait nodes
const brevoJ0 = JSON.stringify({
  sender, to: leadRecipient,
  subject: j0Subject,
  htmlContent: toHtml(parsed.email_bienvenue)
});

const brevoJ2 = JSON.stringify({
  sender, to: leadRecipient,
  subject: j2Subject,
  htmlContent: toHtml(parsed.relance_j2)
});

const brevoJ7 = JSON.stringify({
  sender, to: leadRecipient,
  subject: j7Subject,
  htmlContent: toHtml(parsed.relance_j7)
});

// Email récapitulatif agent
const scoreColor = parsed.score >= 80 ? '#22c55e' : parsed.score >= 50 ? '#f59e0b' : '#6b7280';
const agentHtml = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">
  <h2 style="color:#1e40af;border-bottom:2px solid #e2e8f0;padding-bottom:8px">Nouveau lead — ${tempLabel}</h2>
  <table style="width:100%;border-collapse:collapse;margin-bottom:20px">
    <tr style="background:#f8fafc"><td style="padding:10px;border:1px solid #e2e8f0;font-weight:bold;width:35%">Nom</td><td style="padding:10px;border:1px solid #e2e8f0">${fullName}</td></tr>
    <tr><td style="padding:10px;border:1px solid #e2e8f0;font-weight:bold">Email</td><td style="padding:10px;border:1px solid #e2e8f0"><a href="mailto:${lead.email}">${lead.email}</a></td></tr>
    <tr style="background:#f8fafc"><td style="padding:10px;border:1px solid #e2e8f0;font-weight:bold">Téléphone</td><td style="padding:10px;border:1px solid #e2e8f0">${lead.tel || 'N/A'}</td></tr>
    <tr><td style="padding:10px;border:1px solid #e2e8f0;font-weight:bold">Bien</td><td style="padding:10px;border:1px solid #e2e8f0">${lead.bien || 'N/A'}</td></tr>
    <tr style="background:#f8fafc"><td style="padding:10px;border:1px solid #e2e8f0;font-weight:bold">Ville</td><td style="padding:10px;border:1px solid #e2e8f0">${lead.ville || 'N/A'}</td></tr>
    <tr><td style="padding:10px;border:1px solid #e2e8f0;font-weight:bold">Projet</td><td style="padding:10px;border:1px solid #e2e8f0">${lead.projet || 'N/A'}</td></tr>
    <tr style="background:#f8fafc"><td style="padding:10px;border:1px solid #e2e8f0;font-weight:bold">Source</td><td style="padding:10px;border:1px solid #e2e8f0">${lead.source || 'N/A'}</td></tr>
    <tr><td style="padding:10px;border:1px solid #e2e8f0;font-weight:bold">Score IA</td><td style="padding:10px;border:1px solid #e2e8f0"><strong style="color:${scoreColor}">${parsed.score}/100</strong><br><em>${parsed.score_raison}</em></td></tr>
  </table>
  <h3 style="color:#374151">Message du lead</h3>
  <div style="background:#f8fafc;padding:15px;border-left:4px solid #3b82f6;border-radius:4px">${(lead.message||'Aucun message').replace(/\n/g,'<br>')}</div>
  <p style="color:#9ca3af;font-size:12px;margin-top:20px">Email J0 envoyé · Relances J2 et J7 planifiées automatiquement</p>
</div>`;

const brevoAgent = JSON.stringify({
  sender,
  to: [{ email: agentEmail, name: agentName }],
  subject: `[LeadFlow] Lead ${tempLabel} — ${fullName} (${parsed.score}/100)`,
  htmlContent: agentHtml
});

// Payload LeadFlow (pour enregistrement en base)
const leadflowPayload = JSON.stringify({
  id: lead.id || String(Date.now()),
  prenom: lead.prenom || '',
  nom: lead.nom || '',
  email: lead.email || '',
  tel: lead.tel || '',
  bien: lead.bien || '',
  ville: lead.ville || '',
  source: lead.source || '',
  projet: lead.projet || '',
  message: lead.message || '',
  score: parsed.score,
  score_raison: parsed.score_raison,
  email_bienvenue: parsed.email_bienvenue,
  relance_j2: parsed.relance_j2,
  relance_j7: parsed.relance_j7
});

return [{
  json: {
    id: lead.id || String(Date.now()),
    email: lead.email,
    prenom: lead.prenom,
    nom: lead.nom,
    score: parsed.score,
    temperature: temp,
    // Payloads pré-construits (réutilisés après Wait nodes)
    _leadflow: leadflowPayload,
    _brevo_j0: brevoJ0,
    _brevo_j2: brevoJ2,
    _brevo_j7: brevoJ7,
    _brevo_agent: brevoAgent
  }
}];
